  ('public-health-specialist-moex-00874', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於安慰劑，下列敘述何者錯誤？', '["安慰劑是與實驗品外表相同、味道相同，但不含實驗品內容的替代品", "安慰劑的目的之一是要達成blinding", "即便使用安慰劑控制組，受試者有可能發現自己接受的是實驗品還是安慰劑", "若有標準療法，仍應盡量讓控制組接受安慰劑，以評估實驗品的真正效益（efficacy）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
